import React,{useEffect,useState}from'react';import{createRoot}from'react-dom/client';import{Compass,Search}from'lucide-react';import{loadPublicData,updateCountry,addLocation,updateLocation,updateSettings,addMedia}from'./lib/data';import{supabase,hasSupabase}from'./lib/supabase';import'./styles.css';
const phases={phase1:{duration:'SEP - DEC 2026'},phase2:{duration:'JAN - MARCH'}};const byPhase=(a,p)=>a.filter(c=>c.phase===p);const slugify=s=>String(s||'').toLowerCase().trim().replace(/[^a-z0-9]+/g,'-').replace(/(^-|-$)/g,'');const getCountry=(a,id)=>a.find(c=>c.id===id)||a[0];
function Loading(){return <main className="hero-surface"><section className="hero-layout single"><h1>Loading The 210 Project…</h1></section></main>}function useData(){const[data,setData]=useState(null);async function refresh(){setData(await loadPublicData())}useEffect(()=>{refresh()},[]);return[data,refresh]}
function Crumbs({items}){return <nav className="crumbs"><a href="/">Home</a>{items.map(i=><React.Fragment key={i.href||i.label}> <span>/</span> {i.href?<a href={i.href}>{i.label}</a>:<b>{i.label}</b>}</React.Fragment>)}</nav>}
function RouteMap({countries,selected,setSelected,phase,setPhase,currentId}){const shown=byPhase(countries,phase),pos=phase==='phase1'?{colombia:{left:'43%',top:'16%'},peru:{left:'34%',top:'39%'},argentina:{left:'48%',top:'76%'},brazil:{left:'70%',top:'40%'}}:{vietnam:{left:'36%',top:'61%'},'south-korea':{left:'64%',top:'29%'},japan:{left:'81%',top:'37%'},'hong-kong':{left:'56%',top:'52%'},singapore:{left:'42%',top:'77%'}};return <div className="route-panel"><div className="phase-tabs"><button className={phase==='phase1'?'on':''}onClick={()=>{setPhase('phase1');setSelected(byPhase(countries,'phase1')[0])}}>Phase 1</button><button className={phase==='phase2'?'on':''}onClick={()=>{setPhase('phase2');setSelected(byPhase(countries,'phase2')[0])}}>Phase 2</button></div><div className="panel-head"><span><Compass size={13}/> INTERACTIVE ROUTE</span><span>{phases[phase].duration}</span></div><div className="map-area"><svg className="route-svg"viewBox="0 0 100 100"preserveAspectRatio="none">{phase==='phase1'?<><path className="land"d="M47 5 C58 7 67 14 70 25 C73 37 66 46 61 55 C57 62 59 68 54 75 C50 83 43 98 37 95 C32 92 35 79 31 69 C27 58 21 47 25 37 C29 28 33 22 34 13 C35 7 40 4 47 5 Z"/><path className="trail"d="M43 16 C36 25 33 34 34 39 C39 52 42 64 48 76 C56 62 65 48 70 40"/></>:<><path className="land asia"d="M18 26 C32 12 52 9 68 16 C82 23 93 36 88 49 C84 61 70 59 62 70 C52 84 34 84 25 71 C16 58 7 42 18 26 Z M72 29 C83 32 91 39 92 48 C84 44 78 39 72 29 Z"/><path className="trail"d="M36 61 C46 51 56 39 64 29 C72 31 79 35 81 38 C71 43 62 48 56 52 C48 61 43 71 42 77"/></>}</svg>{shown.map((c,i)=><button key={c.id}onClick={()=>setSelected(c)}className={`marker ${selected?.id===c.id?'selected':''} ${currentId===c.id?'current':''}`}style={pos[c.id]||{left:`${25+i*12}%`,top:'50%'}}><span>{String(c.route_order||i+1).padStart(2,'0')}</span></button>)}</div><div className="map-key"><span className="live-dot"></span> Live location <span className="route-dot"></span> Route stop <span className="selected-dot"></span> Selected</div><div className="map-country-strip">{shown.map(c=><button key={c.id}onClick={()=>setSelected(c)}className={`${selected?.id===c.id?'selected':''} ${currentId===c.id?'current':''}`}><span>{String(c.route_order).padStart(2,'0')}</span><b>{c.name}</b><em>{c.days}d</em></button>)}</div><div className="current-card"><p>{currentId===selected?.id?'LIVE LOCATION':'SELECTED CHAPTER'}</p><h3>{selected?.name}</h3><span>{selected?.current_location||selected?.dates}</span></div></div>}
function Home(){const[data]=useData();const[query,setQuery]=useState('What changed in Peru?');const[phase,setPhase]=useState('phase1');const[selected,setSelected]=useState(null);useEffect(()=>{if(data&&!selected){const c=getCountry(data.countries,data.settings.current_country_id);setSelected(c);setPhase(c.phase)}},[data,selected]);if(!data||!selected)return <Loading/>;const live=data.settings.current_country_id;return <><main className="hero-surface"><section className="hero-layout"><div className="hero-copy"><p className="kicker"><i/> LIVE TRAVEL ARCHIVE</p><h1><span>The</span><em>210</em><span>Project</span></h1><p className="lead">A living record of movement, place and reflection across South America and Asia.</p><div className="hero-actions"><a href="#archive">EXPLORE ARCHIVE ↗</a><a href="/admin"className="watch-link">PRIVATE ADMIN</a></div>{data.usingFallback&&<p className="setup-note">Running on fallback data. Connect Supabase to make it live.</p>}</div><RouteMap countries={data.countries}selected={selected}setSelected={setSelected}phase={phase}setPhase={setPhase}currentId={live}/></section></main><section id="archive"className="cream-section archive-section"><div className="section-inner archive-grid-head"><div><p className="kicker dark"><i/> FIELD ARCHIVE</p><h2>Not a blog.<br/>A memory system.</h2></div><p className="section-note">The whole journey is visible here. Future countries stay quiet and grey until they become live.</p></div><div className="section-inner country-archive-grid">{data.countries.map(c=><a key={c.id}href={`/archive/${c.id}`}className={`country-archive-card ${c.id===live?'live':'muted'}`}><p>{String(c.route_order).padStart(2,'0')} · {c.phase==='phase1'?'PHASE 1':'PHASE 2'}</p><h3>{c.name}</h3><span>{c.id===live?'LIVE NOW':'COMING SOON'}</span><small>{c.summary}</small></a>)}</div></section><section className="companion-section"><div className="companion-inner"><div className="companion-copy"><p className="kicker"><i/> THE ARCHIVE COMPANION</p><h2>Ask the<br/>journey.</h2><p>The companion is wired as a front-end prototype. V5 can connect it to live Supabase data.</p></div><div className="answer-card"><div className="answer-head"><span>● AI COMPANION</span><small>PROTOTYPE</small></div><article><p>RESPONSE</p><h3>{query.toLowerCase().includes('peru')?'Peru is currently the endurance chapter.':'The archive companion reads country pages, location blogs, highlights and reflections.'}</h3></article><div className="ask-bar"><Search size={15}/><input value={query}onChange={e=>setQuery(e.target.value)}/><button>↗</button></div></div></div></section><Footer/></>}
function CountryPage({id}){const[data]=useData();if(!data)return <Loading/>;const country=getCountry(data.countries,id),locs=data.locations.filter(l=>l.country_id===country.id);return <><main className="hero-surface country-hero"><section className="country-hero-inner"><Crumbs items={[{label:country.name}]}/><p className="kicker"><i/> COUNTRY CHAPTER</p><h1>{country.name}</h1><p className="lead">{country.summary}</p></section></main><section className="cream-section"><div className="section-inner country-template"><section><p className="kicker dark"><i/> AI COUNTRY SUMMARY</p><p className="summary-display">{country.summary}</p></section><section><p className="kicker dark"><i/> CURATED TOP MOMENTS</p><div className="highlight-grid">{(country.highlights||[]).map((h,i)=><article key={h}><span>{String(i+1).padStart(2,'0')}</span><h3>{h}</h3></article>)}</div></section><section><p className="kicker dark"><i/> LOCATIONS VISITED</p><div className="location-grid">{locs.map(l=><a key={l.id}href={`/archive/${country.id}/${l.slug}`}><img src={l.hero_image}alt={l.name}/><div><span>{l.date_text}</span><h3>{l.name}</h3><p>{l.summary}</p></div></a>)}</div></section></div></section></>}
function LocationPage({countryId,slug,gallery=false}){const[data]=useData();if(!data)return <Loading/>;const country=getCountry(data.countries,countryId),loc=data.locations.find(l=>l.country_id===country.id&&l.slug===slug)||{},media=data.media.filter(m=>m.location_id===loc.id);if(gallery)return <GalleryPage country={country}loc={loc}media={media}/>;return <><main className="hero-surface location-hero"><section className="detail-layout"><div><Crumbs items={[{label:country.name,href:`/archive/${country.id}`},{label:loc.name||slug}]}/><p className="kicker"><i/> LOCATION STORY</p><h1>{loc.name||slug}</h1><p className="lead">{loc.summary}</p></div><div className="detail-image"><img src={loc.hero_image||'https://images.unsplash.com/photo-1500530855697-b586d89ba3ee?auto=format&fit=crop&w=1200&q=80'}alt={loc.name}/><b>{country.name} · {loc.date_text||''}</b></div></section></main><section className="cream-section"><div className="section-inner location-template"><article><p className="kicker dark"><i/> DETAILED BLOG</p><h2>{loc.name}</h2><p className="blog-copy">{loc.blog}</p>{media.length>0&&<a className="gallery-link"href={`/archive/${country.id}/${loc.slug}/gallery`}>View all photos →</a>}</article><aside><p className="kicker dark"><i/> HIGHLIGHTS</p>{(loc.highlights||[]).map(h=><div className="mini-highlight"key={h}>{h}</div>)}<p className="kicker dark"><i/> PHOTO PREVIEW</p><div className="photo-preview">{media.slice(0,4).map(m=><img key={m.id}src={m.url}alt={m.caption||loc.name}/>)}</div><p className="kicker dark"><i/> TAGS</p><div className="tags">{(loc.tags||[]).map(t=><span key={t}>{t}</span>)}</div></aside></div></section></>}
function GalleryPage({country,loc,media}){return <><main className="hero-surface country-hero"><section className="country-hero-inner"><Crumbs items={[{label:country.name,href:`/archive/${country.id}`},{label:loc.name,href:`/archive/${country.id}/${loc.slug}`},{label:'Gallery'}]}/><p className="kicker"><i/> PHOTO GALLERY</p><h1>{loc.name}</h1><p className="lead">All images uploaded for this location.</p></section></main><section className="cream-section"><div className="section-inner gallery-grid">{media.map(m=><figure key={m.id}><img src={m.url}alt={m.caption||loc.name}/><figcaption>{m.caption}</figcaption></figure>)}</div></section></>}
function Admin(){const[data,refresh]=useData();const[session,setSession]=useState(null),[email,setEmail]=useState(''),[password,setPassword]=useState(''),[msg,setMsg]=useState(''),[busy,setBusy]=useState('');const empty={country_id:'peru',id:'',name:'',slug:'',date_text:'',summary:'',blog:'',hero_image:'',highlights:'',tags:''};const[location,setLocation]=useState(empty),[countryEdit,setCountryEdit]=useState({id:'peru',summary:'',current_location:''}),[files,setFiles]=useState([]);useEffect(()=>{if(!supabase)return;supabase.auth.getSession().then(({data})=>setSession(data.session));const{data:sub}=supabase.auth.onAuthStateChange((_e,s)=>setSession(s));return()=>sub.subscription.unsubscribe()},[]);if(!data)return <Loading/>;function pickLocation(id){const l=data.locations.find(x=>x.id===id);if(!l){setLocation(empty);return}setLocation({...l,highlights:(l.highlights||[]).join(', '),tags:(l.tags||[]).join(', ')})}async function signIn(e){e.preventDefault();if(!hasSupabase){setMsg('Supabase is not configured yet.');return}const{error}=await supabase.auth.signInWithPassword({email,password});setMsg(error?error.message:'Signed in')}async function saveLive(){try{setBusy('live');await updateSettings({current_country_id:countryEdit.id,current_location_slug:slugify(countryEdit.current_location)});setMsg('✓ Live location updated')}catch(e){setMsg(e.message)}finally{setBusy('')}}async function saveCountry(){try{setBusy('country');await updateCountry({id:countryEdit.id,summary:countryEdit.summary,current_location:countryEdit.current_location});setMsg('✓ Country summary saved');refresh()}catch(e){setMsg(e.message)}finally{setBusy('')}}async function saveLocation(){try{setBusy('location');const payload={...location,slug:location.slug||slugify(location.name),highlights:String(location.highlights||'').split(',').map(s=>s.trim()).filter(Boolean),tags:String(location.tags||'').split(',').map(s=>s.trim()).filter(Boolean),sort_order:99,is_published:true};const isEditing=Boolean(payload.id);if(!isEditing){delete payload.id;}let res=isEditing?await updateLocation(payload):await addLocation(payload);if(res.error)throw res.error;let loc=res.data;if(files.length&&hasSupabase){for(const file of files){const path=`${loc.country_id}/${loc.slug}/${Date.now()}-${file.name}`;const up=await supabase.storage.from('trip-media').upload(path,file,{upsert:true});if(up.error)throw up.error;const pub=supabase.storage.from('trip-media').getPublicUrl(path).data.publicUrl;await addMedia({location_id:loc.id,url:pub,file_path:path,caption:file.name,media_type:'photo'});if(!loc.hero_image){await updateLocation({...loc,hero_image:pub});loc={...loc,hero_image:pub}}}}setMsg(isEditing?'✓ Location updated':'✓ Location published');setFiles([]);refresh()}catch(e){setMsg(e.message)}finally{setBusy('')}}return <main className="admin-page"><section className="admin-shell"><a href="/"className="back-link">← Back to public site</a><p className="kicker dark"><i/> PRIVATE ADMIN</p><h1>Manage The 210 Project.</h1>{!session?<form className="admin-card login"onSubmit={signIn}><label>Email</label><input value={email}onChange={e=>setEmail(e.target.value)}/><label>Password</label><input type="password"value={password}onChange={e=>setPassword(e.target.value)}/><button>Sign in</button></form>:<div className="admin-grid"><div className="admin-card"><h2>Live location & country summary</h2><label>Country</label><select value={countryEdit.id}onChange={e=>{const c=getCountry(data.countries,e.target.value);setCountryEdit({id:c.id,summary:c.summary||'',current_location:c.current_location||''})}}>{data.countries.map(c=><option key={c.id}value={c.id}>{c.name}</option>)}</select><label>Current location</label><input value={countryEdit.current_location}onChange={e=>setCountryEdit({...countryEdit,current_location:e.target.value})}/><label>AI country summary</label><textarea value={countryEdit.summary}onChange={e=>setCountryEdit({...countryEdit,summary:e.target.value})}/><button className={busy==='live'?'busy':''}onClick={saveLive}>{busy==='live'?'Saving…':'Set live location'}</button><button className={busy==='country'?'busy':''}onClick={saveCountry}>{busy==='country'?'Saving…':'Save country summary'}</button></div><div className="admin-card"><h2>Add or edit a location page</h2><label>Edit existing location</label><select value={location.id||''}onChange={e=>pickLocation(e.target.value)}><option value="">New location</option>{data.locations.map(l=><option key={l.id}value={l.id}>{getCountry(data.countries,l.country_id).name} / {l.name}</option>)}</select><label>Country</label><select value={location.country_id}onChange={e=>setLocation({...location,country_id:e.target.value})}>{data.countries.map(c=><option key={c.id}value={c.id}>{c.name}</option>)}</select><label>Location name</label><input value={location.name}onChange={e=>setLocation({...location,name:e.target.value,slug:slugify(e.target.value)})}/><label>Slug</label><input value={location.slug}onChange={e=>setLocation({...location,slug:e.target.value})}/><label>Date</label><input value={location.date_text||''}onChange={e=>setLocation({...location,date_text:e.target.value})}/><label>Hero image URL</label><input value={location.hero_image||''}onChange={e=>setLocation({...location,hero_image:e.target.value})}/><label>Summary</label><textarea value={location.summary||''}onChange={e=>setLocation({...location,summary:e.target.value})}/><label>Blog/reflection</label><textarea value={location.blog||''}onChange={e=>setLocation({...location,blog:e.target.value})}/><label>Highlights, comma-separated</label><input value={location.highlights||''}onChange={e=>setLocation({...location,highlights:e.target.value})}/><label>Tags, comma-separated</label><input value={location.tags||''}onChange={e=>setLocation({...location,tags:e.target.value})}/><label>Upload photos from phone</label><input type="file"multiple accept="image/*"onChange={e=>setFiles([...e.target.files])}/><button className={busy==='location'?'busy':''}onClick={saveLocation}>{busy==='location'?'Publishing…':location.id?'Update location':'Publish location'}</button></div></div>}<div className="toast">{msg}</div></section></main>}
function Footer(){return <footer className="footer"><span>▧ THE 210 PROJECT</span><span>A living travel archive.</span><span>V4.2.1</span></footer>}
function Router(){const p=window.location.pathname.split('/').filter(Boolean);if(p[0]==='admin')return <Admin/>;if(p[0]==='archive'&&p[1]&&p[2]&&p[3]==='gallery')return <LocationPage countryId={p[1]} slug={p[2]} gallery/>;if(p[0]==='archive'&&p[1]&&p[2])return <LocationPage countryId={p[1]} slug={p[2]}/>;if(p[0]==='archive'&&p[1])return <CountryPage id={p[1]}/>;return <Home/>}createRoot(document.getElementById('root')).render(<Router/>);
